arguments.file_text:
@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1>Kanban Board</h1>

@if (isLoading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>Error: @errorMessage</p>
        <button class="btn btn-primary" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    <!-- Stats Bar -->
    <div class="stats-bar">
        <div class="stat-item">
            <span class="stat-label">Total</span>
            <span class="stat-value">@filteredTasks.Count</span>
        </div>
        <div class="stat-item">
            <span class="stat-label">To Do</span>
            <span class="stat-value">@TodoTasks.Count()</span>
        </div>
        <div class="stat-item">
            <span class="stat-label">In Progress</span>
            <span class="stat-value">@InProgressTasks.Count()</span>
        </div>
        <div class="stat-item">
            <span class="stat-label">Done</span>
            <span class="stat-value">@DoneTasks.Count()</span>
        </div>
        <div class="stat-item stat-overdue">
            <span class="stat-label">Overdue</span>
            <span class="stat-value">@filteredTasks.Count(t => t.DueDate < DateTime.Today)</span>
        </div>
    </div>

    <!-- Search Bar -->
    <div class="search-bar">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="searchQuery" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="board-columns">
        @foreach (var column in columns)
        {
            var columnTasks = GetColumnTasks(column.Status);
            <div class="board-column">
                <div class="column-header">
                    <h3>@column.Name</h3>
                    <span class="column-count">@columnTasks.Count()</span>
                </div>

                <div class="column-body">
                    @foreach (var task in columnTasks)
                    {
                        <div class="task-card">
                            <div class="task-title">@task.Title</div>
                            <div class="task-assignee">@task.Assignee</div>
                            <span class="priority-badge priority-@task.Priority.ToLowerInvariant()">@task.Priority</span>
                            <div class="task-due">@task.DueDate.ToString("MMM dd")</div>
                            <div class="task-actions">
                                @if (column.Index > 0)
                                {
                                    <button class="btn btn-sm btn-outline-secondary"
                                            disabled="@isBusy"
                                            @onclick="() => MoveTaskAsync(task.Id, columns[column.Index - 1].Status)">
                                        &larr; Move Left
                                    </button>
                                }
                                @if (column.Index < columns.Length - 1)
                                {
                                    <button class="btn btn-sm btn-outline-secondary"
                                            disabled="@isBusy"
                                            @onclick="() => MoveTaskAsync(task.Id, columns[column.Index + 1].Status)">
                                        Move Right &rarr;
                                    </button>
                                }
                            </div>
                        </div>
                    }
                </div>

                @if (addingColumn == column.Status)
                {
                    <div class="add-task-form">
                        <input type="text" class="form-control" placeholder="Title"
                               @bind="newTitle" />
                        <input type="text" class="form-control" placeholder="Assignee"
                               @bind="newAssignee" />
                        <select class="form-control" @bind="newPriority">
                            <option value="High">High</option>
                            <option value="Medium">Medium</option>
                            <option value="Low">Low</option>
                        </select>
                        <input type="date" class="form-control" @bind="newDueDate" />
                        <div class="form-buttons">
                            <button class="btn btn-sm btn-primary" disabled="@isBusy"
                                    @onclick="SaveNewTaskAsync">Save</button>
                            <button class="btn btn-sm btn-secondary"
                                    @onclick="CancelAdd">Cancel</button>
                        </div>
                    </div>
                }
                else
                {
                    <button class="btn btn-sm btn-outline-primary add-task-btn"
                            @onclick="() => StartAdd(column.Status)">
                        + Add Task
                    </button>
                }
            </div>
        }
    </div>
}

@code {
    private record ColumnDef(string Name, string Status, int Index);

    private static readonly ColumnDef[] columns =
    [
        new("To Do", "To Do", 0),
        new("In Progress", "In Progress", 1),
        new("Done", "Done", 2)
    ];

    private List<TaskItem> allTasks = [];
    private bool isLoading = true;
    private bool isBusy;
    private string? errorMessage;
    private string searchQuery = string.Empty;

    // Add-task form state
    private string? addingColumn;
    private string newTitle = string.Empty;
    private string newAssignee = string.Empty;
    private string newPriority = "Medium";
    private DateTime newDueDate = DateTime.Today.AddDays(7);

    private List<TaskItem> filteredTasks =>
        string.IsNullOrWhiteSpace(searchQuery)
            ? allTasks
            : allTasks.Where(t => t.Title.Contains(searchQuery, StringComparison.OrdinalIgnoreCase)).ToList();

    private IEnumerable<TaskItem> TodoTasks => GetColumnTasks("To Do");
    private IEnumerable<TaskItem> InProgressTasks => GetColumnTasks("In Progress");
    private IEnumerable<TaskItem> DoneTasks => GetColumnTasks("Done");

    private IEnumerable<TaskItem> GetColumnTasks(string status) =>
        filteredTasks.Where(t => t.Status == status);

    protected override async Task OnInitializedAsync()
    {
        await LoadTasksAsync();
    }

    private async Task LoadTasksAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        isBusy = true;
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.First(t => t.Id == taskId);
            allTasks[allTasks.IndexOf(task)] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isBusy = false;
        }
    }

    private void StartAdd(string columnStatus)
    {
        addingColumn = columnStatus;
        newTitle = string.Empty;
        newAssignee = string.Empty;
        newPriority = "Medium";
        newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd()
    {
        addingColumn = null;
    }

    private async Task SaveNewTaskAsync()
    {
        if (string.IsNullOrWhiteSpace(newTitle) || addingColumn is null)
            return;

        isBusy = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(newTitle, newAssignee, newPriority, newDueDate);
            // Place the new task in the column where the form was opened
            if (created.Status != addingColumn)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, addingColumn);
                created = created with { Status = addingColumn };
            }
            allTasks.Add(created);
            addingColumn = null;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isBusy = false;
        }
    }
}

.stats-bar {
    display: flex;
    gap: 1rem;
    padding: 0.75rem 1rem;
    background: #f0f4f8;
    border-radius: 8px;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

.stat-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    min-width: 70px;
}

.stat-label {
    font-size: 0.75rem;
    color: #666;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.stat-value {
    font-size: 1.25rem;
    font-weight: 600;
}

.stat-overdue .stat-value {
    color: #dc3545;
}

.search-bar {
    margin-bottom: 1rem;
    max-width: 400px;
}

.board-columns {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
}

.board-column {
    flex: 1;
    background: #f6f8fa;
    border-radius: 8px;
    padding: 0.75rem;
    min-width: 0;
}

.column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

.column-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 600;
}

.column-count {
    background: #d0d7de;
    border-radius: 10px;
    padding: 0.1rem 0.5rem;
    font-size: 0.8rem;
    font-weight: 600;
}

.column-body {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    min-height: 60px;
}

.task-card {
    background: #fff;
    border: 1px solid #d0d7de;
    border-radius: 6px;
    padding: 0.75rem;
}

.task-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.task-assignee {
    font-size: 0.85rem;
    color: #555;
    margin-bottom: 0.35rem;
}

.priority-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    font-weight: 600;
    color: #fff;
    margin-bottom: 0.35rem;
}

.priority-high {
    background-color: #dc3545;
}

.priority-medium {
    background-color: #ffc107;
    color: #333;
}

.priority-low {
    background-color: #28a745;
}

.task-due {
    font-size: 0.8rem;
    color: #666;
    margin-bottom: 0.35rem;
}

.task-actions {
    display: flex;
    gap: 0.35rem;
    flex-wrap: wrap;
}

.add-task-form {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    margin-top: 0.5rem;
    padding: 0.75rem;
    background: #fff;
    border: 1px dashed #aaa;
    border-radius: 6px;
}

.form-buttons {
    display: flex;
    gap: 0.35rem;
}

.add-task-btn {
    width: 100%;
    margin-top: 0.5rem;
}

.board-error {
    padding: 1rem;
    background: #fff3cd;
    border-radius: 6px;
    margin-bottom: 1rem;
}

