toolArgs.file_text:
.stats-bar {
    display: flex;
    gap: 1rem;
    padding: 0.75rem 1rem;
    background: #f0f4f8;
    border-radius: 8px;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

.stat-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    min-width: 70px;
}

.stat-label {
    font-size: 0.75rem;
    color: #666;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.stat-value {
    font-size: 1.25rem;
    font-weight: 600;
}

.stat-overdue .stat-value {
    color: #dc3545;
}

.search-bar {
    margin-bottom: 1rem;
    max-width: 400px;
}

.board-columns {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
}

.board-column {
    flex: 1;
    background: #f6f8fa;
    border-radius: 8px;
    padding: 0.75rem;
    min-width: 0;
}

.column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

.column-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 600;
}

.column-count {
    background: #d0d7de;
    border-radius: 10px;
    padding: 0.1rem 0.5rem;
    font-size: 0.8rem;
    font-weight: 600;
}

.column-body {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    min-height: 60px;
}

.task-card {
    background: #fff;
    border: 1px solid #d0d7de;
    border-radius: 6px;
    padding: 0.75rem;
}

.task-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.task-assignee {
    font-size: 0.85rem;
    color: #555;
    margin-bottom: 0.35rem;
}

.priority-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    font-weight: 600;
    color: #fff;
    margin-bottom: 0.35rem;
}

.priority-high {
    background-color: #dc3545;
}

.priority-medium {
    background-color: #ffc107;
    color: #333;
}

.priority-low {
    background-color: #28a745;
}

.task-due {
    font-size: 0.8rem;
    color: #666;
    margin-bottom: 0.35rem;
}

.task-actions {
    display: flex;
    gap: 0.35rem;
    flex-wrap: wrap;
}

.add-task-form {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    margin-top: 0.5rem;
    padding: 0.75rem;
    background: #fff;
    border: 1px dashed #aaa;
    border-radius: 6px;
}

.form-buttons {
    display: flex;
    gap: 0.35rem;
}

.add-task-btn {
    width: 100%;
    margin-top: 0.5rem;
}

.board-error {
    padding: 1rem;
    background: #fff3cd;
    border-radius: 6px;
    margin-bottom: 1rem;
}

